-- ============================================
-- 算法题库 DDL + 种子数据（多语言版）
-- 语言: Java / Python / JavaScript
-- 自动生成，勿手动编辑
-- ============================================

DROP TABLE IF EXISTS algorithm_problem;
CREATE TABLE algorithm_problem (
    id            BIGINT PRIMARY KEY AUTO_INCREMENT,
    title         VARCHAR(100)  NOT NULL COMMENT '题目标题',
    description   TEXT          NOT NULL COMMENT '题目描述（精简）',
    difficulty    VARCHAR(10)   NOT NULL DEFAULT 'easy' COMMENT 'easy/medium/hard',
    starter_code  JSON          NOT NULL COMMENT '{"java":"...","python":"...","javascript":"..."}',
    test_cases    JSON          NOT NULL COMMENT '[{"input":"stdin","expected":"stdout"}]',
    solution_code JSON          NOT NULL COMMENT '{"java":"...","python":"...","javascript":"..."}',
    category      VARCHAR(50)   COMMENT 'array/string/linkedlist/math/dp',
    created_at    DATETIME      DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='算法题库（多语言）';

-- ============================================================
-- 1. 两数之和 (Array, Easy)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('两数之和',
'给定一个整数数组 nums 和一个目标值 target，找出数组中和为目标值的两个整数的下标。
假设每种输入只有一个答案，同一个元素不能使用两次。

示例：nums = [2,7,11,15], target = 9 → 返回 [0,1]',
'easy',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int[] twoSum(int[] nums, int target) {\\n        // TODO: 实现代码\\n        return new int[0];\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        String[] parts = sc.nextLine().split(\\" \\");\\n        int[] nums = Arrays.stream(parts).mapToInt(Integer::parseInt).toArray();\\n        int target = Integer.parseInt(sc.nextLine());\\n        int[] result = new Solution().twoSum(nums, target);\\n        System.out.println(Arrays.toString(result));\\n    }\\n}", "python": "def two_sum(nums, target):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    nums = list(map(int, input().split()))\\n    target = int(input())\\n    print(two_sum(nums, target))", "javascript": "function twoSum(nums, target) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    const nums = lines[0].split(\\" \\").map(Number);\\n    const target = parseInt(lines[1]);\\n    console.log(JSON.stringify(twoSum(nums, target)));\\n});"}',
'[{"input": "2 7 11 15\\n9", "expected": "[0, 1]"}, {"input": "3 2 4\\n6", "expected": "[1, 2]"}, {"input": "3 3\\n6", "expected": "[0, 1]"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int[] twoSum(int[] nums, int target) {\\n        Map<Integer, Integer> map = new HashMap<>();\\n        for (int i = 0; i < nums.length; i++) {\\n            int c = target - nums[i];\\n            if (map.containsKey(c)) return new int[]{map.get(c), i};\\n            map.put(nums[i], i);\\n        }\\n        return new int[0];\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        String[] parts = sc.nextLine().split(\\" \\");\\n        int[] nums = Arrays.stream(parts).mapToInt(Integer::parseInt).toArray();\\n        int target = Integer.parseInt(sc.nextLine());\\n        System.out.println(Arrays.toString(new Solution().twoSum(nums, target)));\\n    }\\n}", "python": "def two_sum(nums, target):\\n    seen = {}\\n    for i, v in enumerate(nums):\\n        c = target - v\\n        if c in seen:\\n            return [seen[c], i]\\n        seen[v] = i\\n    return []\\n\\nif __name__ == \\"__main__\\":\\n    nums = list(map(int, input().split()))\\n    target = int(input())\\n    print(two_sum(nums, target))", "javascript": "function twoSum(nums, target) {\\n    const map = new Map();\\n    for (let i = 0; i < nums.length; i++) {\\n        const c = target - nums[i];\\n        if (map.has(c)) return [map.get(c), i];\\n        map.set(nums[i], i);\\n    }\\n    return [];\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    const nums = lines[0].split(\\" \\").map(Number);\\n    const target = parseInt(lines[1]);\\n    console.log(JSON.stringify(twoSum(nums, target)));\\n});"}',
'array');

-- ============================================================
-- 2. 两数相加 (Linkedlist, Medium)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('两数相加',
'两个非空链表表示两个非负整数，每位数字按逆序存储。将两数相加并返回一个表示和的链表。

示例：l1=[2,4,3], l2=[5,6,4] → [7,0,8]（342+465=807）',
'medium',
'{"java": "import java.util.*;\\n\\nclass ListNode {\\n    int val;\\n    ListNode next;\\n    ListNode(int x) { val = x; }\\n}\\n\\npublic class Solution {\\n    public ListNode addTwoNumbers(ListNode l1, ListNode l2) {\\n        // TODO: 实现代码\\n        return null;\\n    }\\n\\n    static ListNode buildList(String s) {\\n        if (s.isEmpty()) return null;\\n        String[] p = s.split(\\" \\");\\n        ListNode head = new ListNode(Integer.parseInt(p[0]));\\n        ListNode cur = head;\\n        for (int i = 1; i < p.length; i++) {\\n            cur.next = new ListNode(Integer.parseInt(p[i]));\\n            cur = cur.next;\\n        }\\n        return head;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        ListNode l1 = buildList(sc.nextLine().trim());\\n        ListNode l2 = buildList(sc.nextLine().trim());\\n        ListNode r = new Solution().addTwoNumbers(l1, l2);\\n        StringBuilder sb = new StringBuilder();\\n        while (r != null) {\\n            sb.append(r.val);\\n            if (r.next != null) sb.append(\\" \\");\\n            r = r.next;\\n        }\\n        System.out.println(sb);\\n    }\\n}", "python": "class ListNode:\\n    def __init__(self, x):\\n        self.val = x\\n        self.next = None\\n\\ndef add_two_numbers(l1, l2):\\n    # TODO: 实现代码\\n    pass\\n\\ndef build_list(s):\\n    if not s:\\n        return None\\n    vals = s.split()\\n    head = ListNode(int(vals[0]))\\n    cur = head\\n    for v in vals[1:]:\\n        cur.next = ListNode(int(v))\\n        cur = cur.next\\n    return head\\n\\nif __name__ == \\"__main__\\":\\n    l1 = build_list(input().strip())\\n    l2 = build_list(input().strip())\\n    r = add_two_numbers(l1, l2)\\n    out = []\\n    while r:\\n        out.append(str(r.val))\\n        r = r.next\\n    print(\\" \\".join(out))", "javascript": "class ListNode {\\n    constructor(x) { this.val = x; this.next = null; }\\n}\\n\\nfunction addTwoNumbers(l1, l2) {\\n    // TODO: 实现代码\\n}\\n\\nfunction buildList(s) {\\n    if (!s) return null;\\n    const vals = s.split(\\" \\");\\n    const head = new ListNode(parseInt(vals[0]));\\n    let cur = head;\\n    for (let i = 1; i < vals.length; i++) {\\n        cur.next = new ListNode(parseInt(vals[i]));\\n        cur = cur.next;\\n    }\\n    return head;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    const l1 = buildList(lines[0].trim());\\n    const l2 = buildList(lines[1].trim());\\n    let r = addTwoNumbers(l1, l2);\\n    const out = [];\\n    while (r) { out.push(r.val); r = r.next; }\\n    console.log(out.join(\\" \\"));\\n});"}',
'[{"input": "2 4 3\\n5 6 4", "expected": "7 0 8"}, {"input": "0\\n0", "expected": "0"}, {"input": "9 9 9 9 9 9 9\\n9 9 9 9", "expected": "8 9 9 9 0 0 0 1"}]',
'{"java": "import java.util.*;\\n\\nclass ListNode {\\n    int val;\\n    ListNode next;\\n    ListNode(int x) { val = x; }\\n}\\n\\npublic class Solution {\\n    public ListNode addTwoNumbers(ListNode l1, ListNode l2) {\\n        ListNode dummy = new ListNode(0);\\n        ListNode cur = dummy;\\n        int carry = 0;\\n        while (l1 != null || l2 != null || carry != 0) {\\n            int sum = carry;\\n            if (l1 != null) { sum += l1.val; l1 = l1.next; }\\n            if (l2 != null) { sum += l2.val; l2 = l2.next; }\\n            cur.next = new ListNode(sum % 10);\\n            carry = sum / 10;\\n            cur = cur.next;\\n        }\\n        return dummy.next;\\n    }\\n\\n    static ListNode buildList(String s) {\\n        if (s.isEmpty()) return null;\\n        String[] p = s.split(\\" \\");\\n        ListNode head = new ListNode(Integer.parseInt(p[0]));\\n        ListNode cur = head;\\n        for (int i = 1; i < p.length; i++) {\\n            cur.next = new ListNode(Integer.parseInt(p[i]));\\n            cur = cur.next;\\n        }\\n        return head;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        ListNode l1 = buildList(sc.nextLine().trim());\\n        ListNode l2 = buildList(sc.nextLine().trim());\\n        ListNode r = new Solution().addTwoNumbers(l1, l2);\\n        StringBuilder sb = new StringBuilder();\\n        while (r != null) {\\n            sb.append(r.val);\\n            if (r.next != null) sb.append(\\" \\");\\n            r = r.next;\\n        }\\n        System.out.println(sb);\\n    }\\n}", "python": "class ListNode:\\n    def __init__(self, x):\\n        self.val = x\\n        self.next = None\\n\\ndef add_two_numbers(l1, l2):\\n    dummy = ListNode(0)\\n    cur = dummy\\n    carry = 0\\n    while l1 or l2 or carry:\\n        s = carry\\n        if l1:\\n            s += l1.val\\n            l1 = l1.next\\n        if l2:\\n            s += l2.val\\n            l2 = l2.next\\n        cur.next = ListNode(s % 10)\\n        carry = s // 10\\n        cur = cur.next\\n    return dummy.next\\n\\ndef build_list(s):\\n    if not s:\\n        return None\\n    vals = s.split()\\n    head = ListNode(int(vals[0]))\\n    cur = head\\n    for v in vals[1:]:\\n        cur.next = ListNode(int(v))\\n        cur = cur.next\\n    return head\\n\\nif __name__ == \\"__main__\\":\\n    l1 = build_list(input().strip())\\n    l2 = build_list(input().strip())\\n    r = add_two_numbers(l1, l2)\\n    out = []\\n    while r:\\n        out.append(str(r.val))\\n        r = r.next\\n    print(\\" \\".join(out))", "javascript": "class ListNode {\\n    constructor(x) { this.val = x; this.next = null; }\\n}\\n\\nfunction addTwoNumbers(l1, l2) {\\n    const dummy = new ListNode(0);\\n    let cur = dummy, carry = 0;\\n    while (l1 || l2 || carry) {\\n        let sum = carry;\\n        if (l1) { sum += l1.val; l1 = l1.next; }\\n        if (l2) { sum += l2.val; l2 = l2.next; }\\n        cur.next = new ListNode(sum % 10);\\n        carry = Math.floor(sum / 10);\\n        cur = cur.next;\\n    }\\n    return dummy.next;\\n}\\n\\nfunction buildList(s) {\\n    if (!s) return null;\\n    const vals = s.split(\\" \\");\\n    const head = new ListNode(parseInt(vals[0]));\\n    let cur = head;\\n    for (let i = 1; i < vals.length; i++) {\\n        cur.next = new ListNode(parseInt(vals[i]));\\n        cur = cur.next;\\n    }\\n    return head;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    const l1 = buildList(lines[0].trim());\\n    const l2 = buildList(lines[1].trim());\\n    let r = addTwoNumbers(l1, l2);\\n    const out = [];\\n    while (r) { out.push(r.val); r = r.next; }\\n    console.log(out.join(\\" \\"));\\n});"}',
'linkedlist');

-- ============================================================
-- 3. 无重复字符的最长子串 (String, Medium)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('无重复字符的最长子串',
'给定一个字符串 s，找出其中不含有重复字符的最长子串的长度。

示例：s="abcabcbb" → 3（"abc"）；s="bbbbb" → 1',
'medium',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int lengthOfLongestSubstring(String s) {\\n        // TODO: 实现代码\\n        return 0;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().lengthOfLongestSubstring(sc.nextLine()));\\n    }\\n}", "python": "def length_of_longest_substring(s):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    print(length_of_longest_substring(input()))", "javascript": "function lengthOfLongestSubstring(s) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(lengthOfLongestSubstring(line));\\n});"}',
'[{"input": "abcabcbb", "expected": "3"}, {"input": "bbbbb", "expected": "1"}, {"input": "pwwkew", "expected": "3"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int lengthOfLongestSubstring(String s) {\\n        Set<Character> set = new HashSet<>();\\n        int max = 0, left = 0;\\n        for (int right = 0; right < s.length(); right++) {\\n            while (set.contains(s.charAt(right))) {\\n                set.remove(s.charAt(left++));\\n            }\\n            set.add(s.charAt(right));\\n            max = Math.max(max, right - left + 1);\\n        }\\n        return max;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().lengthOfLongestSubstring(sc.nextLine()));\\n    }\\n}", "python": "def length_of_longest_substring(s):\\n    seen = set()\\n    left = max_len = 0\\n    for right, ch in enumerate(s):\\n        while ch in seen:\\n            seen.remove(s[left])\\n            left += 1\\n        seen.add(ch)\\n        max_len = max(max_len, right - left + 1)\\n    return max_len\\n\\nif __name__ == \\"__main__\\":\\n    print(length_of_longest_substring(input()))", "javascript": "function lengthOfLongestSubstring(s) {\\n    const set = new Set();\\n    let max = 0, left = 0;\\n    for (let right = 0; right < s.length; right++) {\\n        while (set.has(s[right])) {\\n            set.delete(s[left++]);\\n        }\\n        set.add(s[right]);\\n        max = Math.max(max, right - left + 1);\\n    }\\n    return max;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(lengthOfLongestSubstring(line));\\n});"}',
'string');

-- ============================================================
-- 4. 最长回文子串 (String, Medium)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('最长回文子串',
'给定一个字符串 s，找到 s 中最长的回文子串。

示例：s="babad" → "bab" 或 "aba"；s="cbbd" → "bb"',
'medium',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public String longestPalindrome(String s) {\\n        // TODO: 实现代码\\n        return \\"\\";\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().longestPalindrome(sc.nextLine()));\\n    }\\n}", "python": "def longest_palindrome(s):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    print(longest_palindrome(input()))", "javascript": "function longestPalindrome(s) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(longestPalindrome(line));\\n});"}',
'[{"input": "babad", "expected": "bab"}, {"input": "cbbd", "expected": "bb"}, {"input": "a", "expected": "a"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public String longestPalindrome(String s) {\\n        if (s == null || s.length() < 1) return \\"\\";\\n        int start = 0, end = 0;\\n        for (int i = 0; i < s.length(); i++) {\\n            int len1 = expand(s, i, i);\\n            int len2 = expand(s, i, i + 1);\\n            int len = Math.max(len1, len2);\\n            if (len > end - start) {\\n                start = i - (len - 1) / 2;\\n                end = i + len / 2;\\n            }\\n        }\\n        return s.substring(start, end + 1);\\n    }\\n\\n    private int expand(String s, int l, int r) {\\n        while (l >= 0 && r < s.length() && s.charAt(l) == s.charAt(r)) {\\n            l--; r++;\\n        }\\n        return r - l - 1;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().longestPalindrome(sc.nextLine()));\\n    }\\n}", "python": "def longest_palindrome(s):\\n    if not s:\\n        return \\"\\"\\n    start = end = 0\\n    for i in range(len(s)):\\n        len1 = expand(s, i, i)\\n        len2 = expand(s, i, i + 1)\\n        length = max(len1, len2)\\n        if length > end - start:\\n            start = i - (length - 1) // 2\\n            end = i + length // 2\\n    return s[start:end + 1]\\n\\ndef expand(s, l, r):\\n    while l >= 0 and r < len(s) and s[l] == s[r]:\\n        l -= 1\\n        r += 1\\n    return r - l - 1\\n\\nif __name__ == \\"__main__\\":\\n    print(longest_palindrome(input()))", "javascript": "function longestPalindrome(s) {\\n    if (!s) return \\"\\";\\n    let start = 0, end = 0;\\n    for (let i = 0; i < s.length; i++) {\\n        const len1 = expand(s, i, i);\\n        const len2 = expand(s, i, i + 1);\\n        const len = Math.max(len1, len2);\\n        if (len > end - start) {\\n            start = i - Math.floor((len - 1) / 2);\\n            end = i + Math.floor(len / 2);\\n        }\\n    }\\n    return s.substring(start, end + 1);\\n}\\n\\nfunction expand(s, l, r) {\\n    while (l >= 0 && r < s.length && s[l] === s[r]) {\\n        l--; r++;\\n    }\\n    return r - l - 1;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(longestPalindrome(line));\\n});"}',
'string');

-- ============================================================
-- 5. Z 字形变换 (String, Medium)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('Z 字形变换',
'将字符串 s 按 Z 字形排列 numRows 行，然后按行读取返回新字符串。

示例：s="PAYPALISHIRING", numRows=3 → "PAHNAPLSIIGYIR"',
'medium',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public String convert(String s, int numRows) {\\n        // TODO: 实现代码\\n        return \\"\\";\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        String s = sc.nextLine();\\n        int n = Integer.parseInt(sc.nextLine());\\n        System.out.println(new Solution().convert(s, n));\\n    }\\n}", "python": "def convert(s, num_rows):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    s = input()\\n    n = int(input())\\n    print(convert(s, n))", "javascript": "function convert(s, numRows) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    console.log(convert(lines[0], parseInt(lines[1])));\\n});"}',
'[{"input": "PAYPALISHIRING\\n3", "expected": "PAHNAPLSIIGYIR"}, {"input": "PAYPALISHIRING\\n4", "expected": "PINALSIGYAHRPI"}, {"input": "A\\n1", "expected": "A"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public String convert(String s, int numRows) {\\n        if (numRows == 1) return s;\\n        StringBuilder[] rows = new StringBuilder[numRows];\\n        for (int i = 0; i < numRows; i++) rows[i] = new StringBuilder();\\n        int r = 0, dir = -1;\\n        for (char c : s.toCharArray()) {\\n            rows[r].append(c);\\n            if (r == 0 || r == numRows - 1) dir = -dir;\\n            r += dir;\\n        }\\n        StringBuilder result = new StringBuilder();\\n        for (StringBuilder row : rows) result.append(row);\\n        return result.toString();\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        String s = sc.nextLine();\\n        int n = Integer.parseInt(sc.nextLine());\\n        System.out.println(new Solution().convert(s, n));\\n    }\\n}", "python": "def convert(s, num_rows):\\n    if num_rows == 1:\\n        return s\\n    rows = [\\"\\"] * num_rows\\n    r, dir = 0, -1\\n    for c in s:\\n        rows[r] += c\\n        if r == 0 or r == num_rows - 1:\\n            dir = -dir\\n        r += dir\\n    return \\"\\".join(rows)\\n\\nif __name__ == \\"__main__\\":\\n    s = input()\\n    n = int(input())\\n    print(convert(s, n))", "javascript": "function convert(s, numRows) {\\n    if (numRows === 1) return s;\\n    const rows = Array.from({ length: numRows }, () => \\"\\");\\n    let r = 0, dir = -1;\\n    for (const c of s) {\\n        rows[r] += c;\\n        if (r === 0 || r === numRows - 1) dir = -dir;\\n        r += dir;\\n    }\\n    return rows.join(\\"\\");\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    console.log(convert(lines[0], parseInt(lines[1])));\\n});"}',
'string');

-- ============================================================
-- 6. 整数反转 (Math, Easy)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('整数反转',
'给定一个 32 位有符号整数 x，返回数字部分反转后的结果。如果反转后超出 [-2^31, 2^31-1] 范围则返回 0。

示例：123 → 321；-123 → -321；120 → 21',
'easy',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int reverse(int x) {\\n        // TODO: 实现代码\\n        return 0;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().reverse(Integer.parseInt(sc.nextLine())));\\n    }\\n}", "python": "def reverse_integer(x):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    print(reverse_integer(int(input())))", "javascript": "function reverseInteger(x) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(reverseInteger(parseInt(line)));\\n});"}',
'[{"input": "123", "expected": "321"}, {"input": "-123", "expected": "-321"}, {"input": "120", "expected": "21"}, {"input": "0", "expected": "0"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int reverse(int x) {\\n        long result = 0;\\n        while (x != 0) {\\n            result = result * 10 + x % 10;\\n            x /= 10;\\n        }\\n        if (result > Integer.MAX_VALUE || result < Integer.MIN_VALUE) return 0;\\n        return (int) result;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().reverse(Integer.parseInt(sc.nextLine())));\\n    }\\n}", "python": "def reverse_integer(x):\\n    sign = -1 if x < 0 else 1\\n    x = abs(x)\\n    result = 0\\n    while x:\\n        result = result * 10 + x % 10\\n        x //= 10\\n    result *= sign\\n    if result < -2**31 or result > 2**31 - 1:\\n        return 0\\n    return result\\n\\nif __name__ == \\"__main__\\":\\n    print(reverse_integer(int(input())))", "javascript": "function reverseInteger(x) {\\n    const sign = x < 0 ? -1 : 1;\\n    x = Math.abs(x);\\n    let result = 0;\\n    while (x) {\\n        result = result * 10 + x % 10;\\n        x = Math.floor(x / 10);\\n    }\\n    result *= sign;\\n    if (result < -(2**31) || result > 2**31 - 1) return 0;\\n    return result;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(reverseInteger(parseInt(line)));\\n});"}',
'math');

