-- 7. 字符串转换整数 atoi (String, Medium)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('字符串转换整数 atoi',
'实现 myAtoi：丢弃前导空格 → 可选正负号 → 读数字直到非数字 → 截断到 [-2^31, 2^31-1]。

示例："42" → 42；"   -42" → -42；"words and 987" → 0',
'medium',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int myAtoi(String s) {\\n        // TODO: 实现代码\\n        return 0;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().myAtoi(sc.nextLine()));\\n    }\\n}", "python": "def my_atoi(s):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    print(my_atoi(input()))", "javascript": "function myAtoi(s) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(myAtoi(line));\\n});"}',
'[{"input": "42", "expected": "42"}, {"input": "   -42", "expected": "-42"}, {"input": "4193 with words", "expected": "4193"}, {"input": "-91283472332", "expected": "-2147483648"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int myAtoi(String s) {\\n        int i = 0, n = s.length();\\n        while (i < n && s.charAt(i) == '' '') i++;\\n        if (i == n) return 0;\\n        int sign = 1;\\n        if (s.charAt(i) == ''+'' || s.charAt(i) == ''-'') {\\n            sign = s.charAt(i) == ''-'' ? -1 : 1;\\n            i++;\\n        }\\n        long result = 0;\\n        while (i < n && Character.isDigit(s.charAt(i))) {\\n            result = result * 10 + (s.charAt(i) - ''0'');\\n            if (sign * result > Integer.MAX_VALUE) return Integer.MAX_VALUE;\\n            if (sign * result < Integer.MIN_VALUE) return Integer.MIN_VALUE;\\n            i++;\\n        }\\n        return (int)(sign * result);\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().myAtoi(sc.nextLine()));\\n    }\\n}", "python": "def my_atoi(s):\\n    s = s.lstrip()\\n    if not s:\\n        return 0\\n    sign = 1\\n    i = 0\\n    if s[0] in \\"+-\\":\\n        sign = -1 if s[0] == \\"-\\" else 1\\n        i = 1\\n    result = 0\\n    INT_MAX, INT_MIN = 2**31 - 1, -2**31\\n    while i < len(s) and s[i].isdigit():\\n        result = result * 10 + int(s[i])\\n        if sign * result > INT_MAX:\\n            return INT_MAX\\n        if sign * result < INT_MIN:\\n            return INT_MIN\\n        i += 1\\n    return sign * result\\n\\nif __name__ == \\"__main__\\":\\n    print(my_atoi(input()))", "javascript": "function myAtoi(s) {\\n    s = s.trimStart();\\n    if (!s) return 0;\\n    let i = 0, sign = 1;\\n    if (s[i] === \\"+\\" || s[i] === \\"-\\") {\\n        sign = s[i] === \\"-\\" ? -1 : 1;\\n        i++;\\n    }\\n    let result = 0;\\n    const INT_MAX = 2**31 - 1, INT_MIN = -(2**31);\\n    while (i < s.length && s[i] >= \\"0\\" && s[i] <= \\"9\\") {\\n        result = result * 10 + parseInt(s[i]);\\n        if (sign * result > INT_MAX) return INT_MAX;\\n        if (sign * result < INT_MIN) return INT_MIN;\\n        i++;\\n    }\\n    return sign * result;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(myAtoi(line));\\n});"}',
'string');

-- ============================================================
-- 8. 回文数 (Math, Easy)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('回文数',
'给定一个整数 x，判断它是否是回文整数。

示例：121 → true；-121 → false；10 → false',
'easy',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public boolean isPalindrome(int x) {\\n        // TODO: 实现代码\\n        return false;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().isPalindrome(Integer.parseInt(sc.nextLine())));\\n    }\\n}", "python": "def is_palindrome(x):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    print(is_palindrome(int(input())))", "javascript": "function isPalindrome(x) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(isPalindrome(parseInt(line)));\\n});"}',
'[{"input": "121", "expected": "true"}, {"input": "-121", "expected": "false"}, {"input": "10", "expected": "false"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public boolean isPalindrome(int x) {\\n        if (x < 0 || (x % 10 == 0 && x != 0)) return false;\\n        int rev = 0;\\n        while (x > rev) {\\n            rev = rev * 10 + x % 10;\\n            x /= 10;\\n        }\\n        return x == rev || x == rev / 10;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().isPalindrome(Integer.parseInt(sc.nextLine())));\\n    }\\n}", "python": "def is_palindrome(x):\\n    if x < 0 or (x % 10 == 0 and x != 0):\\n        return False\\n    rev = 0\\n    while x > rev:\\n        rev = rev * 10 + x % 10\\n        x //= 10\\n    return x == rev or x == rev // 10\\n\\nif __name__ == \\"__main__\\":\\n    print(is_palindrome(int(input())))", "javascript": "function isPalindrome(x) {\\n    if (x < 0 || (x % 10 === 0 && x !== 0)) return false;\\n    let rev = 0;\\n    while (x > rev) {\\n        rev = rev * 10 + x % 10;\\n        x = Math.floor(x / 10);\\n    }\\n    return x === rev || x === Math.floor(rev / 10);\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    console.log(isPalindrome(parseInt(line)));\\n});"}',
'math');

-- ============================================================
-- 9. 正则表达式匹配 (Dp, Hard)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('正则表达式匹配',
'实现支持 . 和 * 的正则匹配。. 匹配任意单字符，* 匹配零个或多个前面的元素，需完全匹配整个字符串。

示例：s="aa", p="a*" → true；s="ab", p=".*" → true；s="mississippi", p="mis*is*p*." → false',
'hard',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public boolean isMatch(String s, String p) {\\n        // TODO: 实现代码\\n        return false;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().isMatch(sc.nextLine(), sc.nextLine()));\\n    }\\n}", "python": "def is_match(s, p):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    s = input()\\n    p = input()\\n    print(is_match(s, p))", "javascript": "function isMatch(s, p) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    console.log(isMatch(lines[0], lines[1]));\\n});"}',
'[{"input": "aa\\na", "expected": "false"}, {"input": "aa\\na*", "expected": "true"}, {"input": "ab\\n.*", "expected": "true"}, {"input": "aab\\nc*a*b", "expected": "true"}, {"input": "mississippi\\nmis*is*p*.", "expected": "false"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public boolean isMatch(String s, String p) {\\n        int m = s.length(), n = p.length();\\n        boolean[][] dp = new boolean[m + 1][n + 1];\\n        dp[0][0] = true;\\n        for (int j = 1; j <= n; j++) {\\n            if (p.charAt(j - 1) == ''*'') dp[0][j] = dp[0][j - 2];\\n        }\\n        for (int i = 1; i <= m; i++) {\\n            for (int j = 1; j <= n; j++) {\\n                if (p.charAt(j - 1) == ''*'') {\\n                    dp[i][j] = dp[i][j - 2];\\n                    if (p.charAt(j - 2) == ''.'' || p.charAt(j - 2) == s.charAt(i - 1)) {\\n                        dp[i][j] = dp[i][j] || dp[i - 1][j];\\n                    }\\n                } else if (p.charAt(j - 1) == ''.'' || p.charAt(j - 1) == s.charAt(i - 1)) {\\n                    dp[i][j] = dp[i - 1][j - 1];\\n                }\\n            }\\n        }\\n        return dp[m][n];\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        System.out.println(new Solution().isMatch(sc.nextLine(), sc.nextLine()));\\n    }\\n}", "python": "def is_match(s, p):\\n    m, n = len(s), len(p)\\n    dp = [[False] * (n + 1) for _ in range(m + 1)]\\n    dp[0][0] = True\\n    for j in range(1, n + 1):\\n        if p[j - 1] == \\"*\\":\\n            dp[0][j] = dp[0][j - 2]\\n    for i in range(1, m + 1):\\n        for j in range(1, n + 1):\\n            if p[j - 1] == \\"*\\":\\n                dp[i][j] = dp[i][j - 2]\\n                if p[j - 2] == \\".\\" or p[j - 2] == s[i - 1]:\\n                    dp[i][j] = dp[i][j] or dp[i - 1][j]\\n            elif p[j - 1] == \\".\\" or p[j - 1] == s[i - 1]:\\n                dp[i][j] = dp[i - 1][j - 1]\\n    return dp[m][n]\\n\\nif __name__ == \\"__main__\\":\\n    s = input()\\n    p = input()\\n    print(is_match(s, p))", "javascript": "function isMatch(s, p) {\\n    const m = s.length, n = p.length;\\n    const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(false));\\n    dp[0][0] = true;\\n    for (let j = 1; j <= n; j++) {\\n        if (p[j - 1] === \\"*\\") dp[0][j] = dp[0][j - 2];\\n    }\\n    for (let i = 1; i <= m; i++) {\\n        for (let j = 1; j <= n; j++) {\\n            if (p[j - 1] === \\"*\\") {\\n                dp[i][j] = dp[i][j - 2];\\n                if (p[j - 2] === \\".\\" || p[j - 2] === s[i - 1]) {\\n                    dp[i][j] = dp[i][j] || dp[i - 1][j];\\n                }\\n            } else if (p[j - 1] === \\".\\" || p[j - 1] === s[i - 1]) {\\n                dp[i][j] = dp[i - 1][j - 1];\\n            }\\n        }\\n    }\\n    return dp[m][n];\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nconst lines = [];\\nrl.on(\\"line\\", line => lines.push(line));\\nrl.on(\\"close\\", () => {\\n    console.log(isMatch(lines[0], lines[1]));\\n});"}',
'dp');

-- ============================================================
-- 10. 盛最多水的容器 (Array, Medium)
-- ============================================================
INSERT INTO algorithm_problem (title, description, difficulty, starter_code, test_cases, solution_code, category) VALUES
('盛最多水的容器',
'给定长度为 n 的数组 height，找出两条线使它们与 x 轴构成的容器能容纳最多的水。

示例：[1,8,6,2,5,4,8,3,7] → 49',
'medium',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int maxArea(int[] height) {\\n        // TODO: 实现代码\\n        return 0;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        int[] h = Arrays.stream(sc.nextLine().split(\\" \\")).mapToInt(Integer::parseInt).toArray();\\n        System.out.println(new Solution().maxArea(h));\\n    }\\n}", "python": "def max_area(height):\\n    # TODO: 实现代码\\n    pass\\n\\nif __name__ == \\"__main__\\":\\n    h = list(map(int, input().split()))\\n    print(max_area(h))", "javascript": "function maxArea(height) {\\n    // TODO: 实现代码\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    const h = line.split(\\" \\").map(Number);\\n    console.log(maxArea(h));\\n});"}',
'[{"input": "1 8 6 2 5 4 8 3 7", "expected": "49"}, {"input": "1 1", "expected": "1"}, {"input": "4 3 2 1 4", "expected": "16"}]',
'{"java": "import java.util.*;\\n\\npublic class Solution {\\n    public int maxArea(int[] height) {\\n        int max = 0, l = 0, r = height.length - 1;\\n        while (l < r) {\\n            int area = Math.min(height[l], height[r]) * (r - l);\\n            max = Math.max(max, area);\\n            if (height[l] < height[r]) l++;\\n            else r--;\\n        }\\n        return max;\\n    }\\n\\n    public static void main(String[] args) {\\n        Scanner sc = new Scanner(System.in);\\n        int[] h = Arrays.stream(sc.nextLine().split(\\" \\")).mapToInt(Integer::parseInt).toArray();\\n        System.out.println(new Solution().maxArea(h));\\n    }\\n}", "python": "def max_area(height):\\n    l, r = 0, len(height) - 1\\n    ans = 0\\n    while l < r:\\n        area = min(height[l], height[r]) * (r - l)\\n        ans = max(ans, area)\\n        if height[l] < height[r]:\\n            l += 1\\n        else:\\n            r -= 1\\n    return ans\\n\\nif __name__ == \\"__main__\\":\\n    h = list(map(int, input().split()))\\n    print(max_area(h))", "javascript": "function maxArea(height) {\\n    let l = 0, r = height.length - 1, max = 0;\\n    while (l < r) {\\n        const area = Math.min(height[l], height[r]) * (r - l);\\n        max = Math.max(max, area);\\n        if (height[l] < height[r]) l++;\\n        else r--;\\n    }\\n    return max;\\n}\\n\\nconst readline = require(\\"readline\\");\\nconst rl = readline.createInterface({ input: process.stdin });\\nrl.on(\\"line\\", line => {\\n    const h = line.split(\\" \\").map(Number);\\n    console.log(maxArea(h));\\n});"}',
'array');

